{"content":"#include <cuda_fp16.h>
#include <cuda_runtime.h>

// Tile sizes optimized for A100
#define TILE_M 128
#define TILE_N 128
#define TILE_K 32
#define THREAD_M 8
#define THREAD_N 8
#define THREADS 256

// Convert half to float for accumulation
__device__ __forceinline__ float h2f(half h) {
    return __half2float(h);
}

// BMM kernel using tiled computation with shared memory
__global__ void bmm_kernel(
    const half* __restrict__ A,  // [batch, m, k]
    const half* __restrict__ B,  // [batch, k, n]
    float* __restrict__ C,       // [batch, m, n]
    int batch,
    int m,
    int k,
    int n
) {
    // Compute batch index
    int batch_idx = blockIdx.z;
    if (batch_idx >= batch) return;

    // Compute output tile position
    int tile_row = blockIdx.y;
    int tile_col = blockIdx.x;

    // Thread position within block
    int tid = threadIdx.x;
    int thread_row = tid / 16;
    int thread_col = tid % 16;

    // Shared memory for tiles
    __shared__ half As[TILE_M][TILE_K];
    __shared__ half Bs[TILE_K][TILE_N];

    // Register file for accumulation
    float acc[THREAD_M][THREAD_N] = {0.0f};

    // Base pointers for this batch
    const half* A_batch = A + batch_idx * m * k;
    const half* B_batch = B + batch_idx * k * n;
    float* C_batch = C + batch_idx * m * n;

    // Starting positions in output
    int base_row = tile_row * TILE_M;
    int base_col = tile_col * TILE_N;

    // Loop over k dimension in tiles
    for (int kt = 0; kt < k; kt += TILE_K) {
        // Load A tile into shared memory
        // Each thread loads multiple elements
        for (int i = tid; i < TILE_M * TILE_K; i += THREADS) {
            int row = i / TILE_K;
            int col = i % TILE_K;
            int global_row = base_row + row;
            int global_col = kt + col;

            if (global_row < m && global_col < k) {
                As[row][col] = A_batch[global_row * k + global_col];
            } else {
                As[row][col] = __float2half(0.0f);
            }
        }

        // Load B tile into shared memory
        for (int i = tid; i < TILE_K * TILE_N; i += THREADS) {
            int row = i / TILE_N;
            int col = i % TILE_N;
            int global_row = kt + row;
            int global_col = base_col + col;

            if (global_row < k && global_col < n) {
                Bs[row][col] = B_batch[global_row * n + global_col];
            } else {
                Bs[row][col] = __float2half(0.0f);
            }
        }

        __syncthreads();

        // Compute partial products
        // Each thread computes THREAD_M x THREAD_N outputs
        for (int i = 0; i < THREAD_M; i++) {
            for (int j = 0; j < THREAD_N; j++) {
                int row = thread_row * THREAD_M + i;
                int col = thread_col * THREAD_N + j;

                if (row < TILE_M && col < TILE_N) {
                    for (int kk = 0; kk < TILE_K; kk++) {
                        acc[i][j] += h2f(As[row][kk]) * h2f(Bs[kk][col]);
                    }
                }
            }
        }

        __syncthreads();
    }

    // Write results to global memory
    for (int i = 0; i < THREAD_M; i++) {
        for (int j = 0; j < THREAD_N; j++) {
            int row = base_row + thread_row * THREAD_M + i;
            int col = base_col + thread_col * THREAD_N + j;

            if (row < m && col < n) {
                C_batch[row * n + col] = acc[i][j];
            }
        }
    }
}

extern "C" {
    void kernel(
        const half* A,
        const half* B, 
        float* C,
        int batch,
        int m,
        int k,
        int n
    ) {
        // Grid dimensions
        dim3 grid(
            (n + TILE_N - 1) / TILE_N,
            (m + TILE_M - 1) / TILE_M,
            batch
        );
        dim3 block(THREADS);

        bmm_kernel<<<grid, block>>>(A, B, C, batch, m, k, n);
    }
}
